import{_ as a,c as o,o as s,aj as t}from"./chunks/framework.ifWuP3HN.js";const g=JSON.parse('{"title":"Unidad 6: Almacenamiento y formatos de intercambio de datos","description":"","frontmatter":{},"headers":[],"relativePath":"contenidos/6-bases_datos.md","filePath":"contenidos/6-bases_datos.md"}'),n={name:"contenidos/6-bases_datos.md"};function r(l,e,i,d,c,u){return s(),o("div",null,e[0]||(e[0]=[t(`<h1 id="unidad-6-almacenamiento-y-formatos-de-intercambio-de-datos" tabindex="-1">Unidad 6: Almacenamiento y formatos de intercambio de datos <a class="header-anchor" href="#unidad-6-almacenamiento-y-formatos-de-intercambio-de-datos" aria-label="Permalink to &quot;Unidad 6: Almacenamiento y formatos de intercambio de datos&quot;">​</a></h1><h2 id="resultado-de-aprendizaje" tabindex="-1">Resultado de aprendizaje <a class="header-anchor" href="#resultado-de-aprendizaje" aria-label="Permalink to &quot;Resultado de aprendizaje&quot;">​</a></h2><p><strong>RA6: Gestiona la información en formatos de intercambio de datos analizando y utilizando tecnologías de almacenamiento y lenguajes de consulta.</strong></p><h2 id="criterios-de-evaluacion" tabindex="-1">Criterios de Evaluación <a class="header-anchor" href="#criterios-de-evaluacion" aria-label="Permalink to &quot;Criterios de Evaluación&quot;">​</a></h2><p>Para superar esta unidad, evaluaremos si:</p><ul><li><strong>a)</strong> Se han identificado los principales métodos de almacenamiento de la información.</li><li><strong>b)</strong> Se han identificado las ventajas e inconvenientes de almacenar información en formatos de intercambio de datos.</li><li><strong>c)</strong> Se han establecido tecnologías eficientes de almacenamiento en función de sus características.</li><li><strong>d)</strong> Se han identificado lenguajes y herramientas para el tratamiento y almacenamiento de información.</li><li><strong>e)</strong> Se han utilizado lenguajes de consulta y manipulación.</li><li><strong>f)</strong> Se han utilizado sistemas gestores de bases de datos relacionales (SGBDR).</li><li><strong>g)</strong> Se han utilizado técnicas para crear documentos de intercambio (JSON) a partir de bases de datos relacionales.</li><li><strong>h)</strong> Se han identificado las características de los sistemas gestores de bases de datos nativas (NoSQL).</li><li><strong>i)</strong> Se han utilizado herramientas para gestionar la información en bases de datos nativas.</li></ul><h2 id="temporalizacion-y-estructura-6-horas" tabindex="-1">Temporalización y estructura (6 horas) <a class="header-anchor" href="#temporalizacion-y-estructura-6-horas" aria-label="Permalink to &quot;Temporalización y estructura (6 horas)&quot;">​</a></h2><table tabindex="0"><thead><tr><th><strong>Sesión</strong></th><th><strong>Título</strong></th><th><strong>Duración</strong></th><th><strong>Criterios</strong></th></tr></thead><tbody><tr><td><strong>Sesión 1</strong></td><td>El problema del fichero plano y la necesidad de las BBDD</td><td>1h</td><td>a, b, c</td></tr><tr><td><strong>Sesión 2</strong></td><td>SQLite y DB Browser: Nuestra primera base de datos profesional</td><td>1h</td><td>d, f</td></tr><tr><td><strong>Sesión 3</strong></td><td>El núcleo: SQL Avanzado y Funciones JSON</td><td>2h</td><td>e, g</td></tr><tr><td><strong>Sesión 4</strong></td><td>Bases de Datos Documentales: El mundo de MongoDB Atlas</td><td>1h</td><td>h, i</td></tr><tr><td><strong>Sesión 5</strong></td><td>Proyecto Final: GameVault</td><td>1h</td><td>Todos</td></tr></tbody></table><h2 id="indice-de-contenidos" tabindex="-1">Índice de contenidos <a class="header-anchor" href="#indice-de-contenidos" aria-label="Permalink to &quot;Índice de contenidos&quot;">​</a></h2><ol><li><strong>Introducción: El salto al mundo profesional</strong><ul><li>De <code>db.json</code> a un Sistema Gestor de Base de Datos.</li><li>¿Por qué JSON-Server ya no es suficiente?</li></ul></li><li><strong>Bases de Datos Relacionales (SQLite)</strong><ul><li>Instalación y uso de DB Browser for SQLite.</li><li>Creación de tablas y tipos de datos para videojuegos.</li></ul></li><li><strong>Consultas y Extracción de Datos</strong><ul><li>Repaso de SQL: Filtrando nuestro catálogo.</li><li>Generación de JSON desde SQL: <code>json_object</code> y <code>json_group_array</code>.</li><li>Importación y exportación de datos.</li></ul></li><li><strong>Bases de Datos NoSQL (MongoDB)</strong><ul><li>Concepto de base de datos documental.</li><li>Uso de MongoDB Atlas (Cloud).</li><li>Gestión de documentos JSON en la nube.</li></ul></li><li><strong>Proyecto Final: GameVault</strong><ul><li>Integración de SQLite y MongoDB.</li></ul></li></ol><blockquote><p>💡 <strong>Nota para el alumno:</strong> A lo largo de esta unidad, recordad que aunque cambie la forma de guardar los datos, vuestro conocimiento de <strong>JSON</strong> y <strong>fetch</strong> sigue siendo la pieza clave. Solo vamos a cambiar el &quot;almacén&quot; para que vuestras aplicaciones sean mucho más potentes.</p></blockquote><h2 id="_1-el-problema-del-fichero-plano" tabindex="-1">1. El problema del fichero plano <a class="header-anchor" href="#_1-el-problema-del-fichero-plano" aria-label="Permalink to &quot;1. El problema del fichero plano&quot;">​</a></h2><h3 id="_1-1-de-juguetes-a-herramientas-profesionales" tabindex="-1">1.1. De &quot;juguetes&quot; a herramientas profesionales <a class="header-anchor" href="#_1-1-de-juguetes-a-herramientas-profesionales" aria-label="Permalink to &quot;1.1. De &quot;juguetes&quot; a herramientas profesionales&quot;">​</a></h3><p>Hasta ahora habéis usado <strong>JSON-Server</strong> como si fuera un servidor real. En vuestros proyectos de videojuegos, simplemente hacíais un <code>fetch</code> a un puerto y los datos aparecían. Pero la realidad es que JSON-Server es solo un simulador que lee y escribe en un fichero llamado <code>db.json</code>.</p><p>En el mundo real, los datos no &quot;viven&quot; en un fichero de texto. Se guardan en <strong>Sistemas Gestores de Bases de Datos (SGBD)</strong>.</p><table tabindex="0"><thead><tr><th><strong>ANTES</strong></th><th><strong>AHORA (Lo que viene)</strong></th></tr></thead><tbody><tr><td><code>fetch</code> → <strong>JSON-Server</strong> → <code>db.json</code></td><td><code>fetch</code> → <strong>Servidor (Node/Java)</strong> → <strong>Base de Datos</strong></td></tr></tbody></table><blockquote><p>💡 <strong>Nota:</strong> Fíjate que el <code>fetch</code> y el objeto JSON que recibes en JavaScript <strong>no van a cambiar</strong>. Lo que cambia es &quot;la cocina&quot;: dónde y cómo se cocinan esos datos antes de enviarlos.</p></blockquote><h3 id="_1-2-el-problema-de-los-ficheros-planos-db-json" tabindex="-1">1.2. El problema de los ficheros planos (<code>db.json</code>) <a class="header-anchor" href="#_1-2-el-problema-de-los-ficheros-planos-db-json" aria-label="Permalink to &quot;1.2. El problema de los ficheros planos (\`db.json\`)&quot;">​</a></h3><p>Un fichero <code>db.json</code> es lo que llamamos un <strong>fichero plano</strong>. Imagina que tu aplicación de videojuegos tiene éxito y pasan tres cosas:</p><ol><li><strong>El problema de la Concurrencia:</strong> Dos jugadores intentan actualizar su puntuación a la vez. El sistema abre el fichero <code>db.json</code>, uno escribe, el otro escribe... y ¡PUM!, el fichero se corrompe o uno de los dos borra los datos del otro.</li><li><strong>El problema del Rendimiento:</strong> Tienes 50.000 videojuegos en tu lista. Para buscar &quot;Zelda&quot;, el ordenador tiene que leer el fichero desde la primera línea hasta encontrarlo. Es como buscar un nombre en un libro de 1.000 páginas leyendo cada palabra.</li><li><strong>El problema de la Integridad:</strong> Si alguien abre el fichero y borra una coma <code>,</code> o una llave <code>}</code> sin querer, <strong>toda la aplicación deja de funcionar</strong>.</li></ol><h3 id="_1-3-ventajas-e-inconvenientes-¿cuando-usar-cada-uno" tabindex="-1">1.3. Ventajas e inconvenientes: ¿Cuándo usar cada uno? <a class="header-anchor" href="#_1-3-ventajas-e-inconvenientes-¿cuando-usar-cada-uno" aria-label="Permalink to &quot;1.3. Ventajas e inconvenientes: ¿Cuándo usar cada uno?&quot;">​</a></h3><p>No siempre vamos a usar una base de datos gigante. Hay que saber elegir.</p><h4 id="formato-de-intercambio-json" tabindex="-1"><strong>Formato de intercambio (JSON)</strong> <a class="header-anchor" href="#formato-de-intercambio-json" aria-label="Permalink to &quot;**Formato de intercambio (JSON)**&quot;">​</a></h4><ul><li><strong>Ventaja:</strong> Es el lenguaje universal de la web. JavaScript lo entiende de forma nativa.</li><li><strong>Inconveniente:</strong> No sirve para gestionar grandes volúmenes de datos ni relaciones complejas de forma segura.</li></ul><h4 id="base-de-datos-relacional-sql" tabindex="-1"><strong>Base de Datos (Relacional - SQL)</strong> <a class="header-anchor" href="#base-de-datos-relacional-sql" aria-label="Permalink to &quot;**Base de Datos (Relacional - SQL)**&quot;">​</a></h4><ul><li><strong>Ventaja:</strong> Extremadamente rápida (usa índices, como el índice de un libro), segura y permite que miles de usuarios entren a la vez.</li><li><strong>Inconveniente:</strong> Es más compleja de configurar y requiere aprender un lenguaje nuevo (SQL).</li></ul><h3 id="_1-4-¿como-elegimos-la-tecnologia-adecuada" tabindex="-1">1.4. ¿Cómo elegimos la tecnología adecuada? <a class="header-anchor" href="#_1-4-¿como-elegimos-la-tecnologia-adecuada" aria-label="Permalink to &quot;1.4. ¿Cómo elegimos la tecnología adecuada?&quot;">​</a></h3><p>Para vuestro proyecto de videojuegos, vamos a ver dos tipos de tecnologías que dominan el mercado actual:</p><ol><li><strong>SQLite:</strong> Es una base de datos relacional. Todo se guarda en un archivo, pero ese archivo está optimizado para que el acceso sea instantáneo. Es perfecta para aplicaciones móviles o proyectos pequeños/medianos.</li><li><strong>MongoDB:</strong> Es una base de datos &quot;NoSQL&quot;. En lugar de tablas, guarda directamente &quot;documentos&quot; que se parecen muchísimo a vuestros objetos JSON. Es ideal cuando los datos cambian mucho o no tienen una estructura fija.</li></ol><blockquote><p>⚠️ <strong>Cuidado:</strong> Un error común es pensar que por usar una Base de Datos ya no necesitamos JSON. ¡Al revés! La base de datos <strong>guarda</strong> los videojuegos y el servidor los <strong>convierte a JSON</strong> para que tu código de JavaScript los pueda pintar en la web.</p></blockquote><h3 id="comparativa-visual" tabindex="-1">Comparativa visual <a class="header-anchor" href="#comparativa-visual" aria-label="Permalink to &quot;Comparativa visual&quot;">​</a></h3><p>Imagina que queremos guardar este videojuego:</p><p><strong>En <code>db.json</code> (Fichero plano):</strong></p><p>JSON</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{</span></span>
<span class="line"><span>  &quot;id&quot;: 1,</span></span>
<span class="line"><span>  &quot;titulo&quot;: &quot;Elden Ring&quot;,</span></span>
<span class="line"><span>  &quot;genero&quot;: &quot;Accion&quot;,</span></span>
<span class="line"><span>  &quot;precio&quot;: 59.99</span></span>
<span class="line"><span>}</span></span></code></pre></div><p><em>Si el fichero mide 100MB, buscar este objeto es lento.</em></p><p><strong>En Base de Datos (SQLite):</strong></p><table tabindex="0"><thead><tr><th><strong>id</strong></th><th><strong>titulo</strong></th><th><strong>genero</strong></th><th><strong>precio</strong></th></tr></thead><tbody><tr><td>1</td><td>Elden Ring</td><td>Accion</td><td>59.99</td></tr></tbody></table><p><em>Aunque la base de datos mida 10GB, encontrar el <code>id: 1</code> es casi instantáneo gracias a que el sistema sabe exactamente en qué &quot;página&quot; está.</em></p><h2 id="_2-sqlite-y-db-browser-crear-la-bd" tabindex="-1">2. SQLite y DB Browser: crear la BD <a class="header-anchor" href="#_2-sqlite-y-db-browser-crear-la-bd" aria-label="Permalink to &quot;2. SQLite y DB Browser: crear la BD&quot;">​</a></h2><h3 id="_2-1-la-herramienta-¿por-que-sqlite" tabindex="-1">2.1. La herramienta: ¿Por qué SQLite? <a class="header-anchor" href="#_2-1-la-herramienta-¿por-que-sqlite" aria-label="Permalink to &quot;2.1. La herramienta: ¿Por qué SQLite?&quot;">​</a></h3><p>Para gestionar datos de forma profesional necesitamos un <strong>SGBDR</strong> (Sistema Gestor de Bases de Datos Relacionales). A diferencia de Oracle o MySQL, que requieren instalar servidores complejos, <strong>SQLite</strong> guarda toda la base de datos en un único archivo (con extensión <code>.db</code> o <code>.sqlite</code>).</p><p>Es la base de datos más usada del mundo: está en tu móvil Android/iPhone, en tu navegador Chrome y hasta en los coches.</p><p>Para ver y tocar esos datos, usaremos <strong>DB Browser for SQLite</strong>. Es como el &quot;Explorador de Archivos&quot; pero para bases de datos.</p><h3 id="_2-2-tipos-de-datos-en-sqlite" tabindex="-1">2.2. Tipos de datos en SQLite <a class="header-anchor" href="#_2-2-tipos-de-datos-en-sqlite" aria-label="Permalink to &quot;2.2. Tipos de datos en SQLite&quot;">​</a></h3><p>Antes de crear nuestra tabla de videojuegos, debemos entender que las bases de datos son muy &quot;especiales&quot; con el tipo de información que guardan. No vale todo.</p><table tabindex="0"><thead><tr><th><strong>Tipo en SQLite</strong></th><th><strong>¿Qué guarda?</strong></th><th><strong>Equivalente en JavaScript/JSON</strong></th></tr></thead><tbody><tr><td><strong>INTEGER</strong></td><td>Números enteros (sin decimales).</td><td><code>Number</code> (p. ej. 2024)</td></tr><tr><td><strong>TEXT</strong></td><td>Cadenas de texto.</td><td><code>String</code> (p. ej. &quot;Zelda&quot;)</td></tr><tr><td><strong>REAL</strong></td><td>Números con decimales.</td><td><code>Number</code> (p. ej. 59.99)</td></tr><tr><td><strong>BLOB</strong></td><td>Datos binarios (imágenes, archivos).</td><td><em>No lo usaremos de momento</em></td></tr></tbody></table><blockquote><p>⚠️ <strong>Cuidado:</strong> A diferencia de JavaScript, donde una variable puede ser un número y luego un texto, en una base de datos, si dices que la columna <code>precio</code> es <strong>REAL</strong>, no podrás meterle el texto &quot;Gratis&quot;. Esto nos ayuda a evitar errores en nuestros datos.</p></blockquote><h3 id="_2-3-paso-a-paso-creando-gamevault" tabindex="-1">2.3. Paso a paso: Creando &quot;GameVault&quot; <a class="header-anchor" href="#_2-3-paso-a-paso-creando-gamevault" aria-label="Permalink to &quot;2.3. Paso a paso: Creando &quot;GameVault&quot;&quot;">​</a></h3><p>Vamos a crear nuestra infraestructura. Sigue estos pasos en DB Browser:</p><ol><li><strong>Crear el archivo:</strong> Haz clic en <strong>&quot;Nueva base de datos&quot;</strong> y guárdala como <code>gamevault.db</code> en tu carpeta de proyecto.</li><li><strong>Definir la tabla:</strong> Se abrirá una ventana para crear una tabla. Llámala <code>videojuegos</code>.</li><li><strong>Añadir los campos (columnas):</strong><ul><li><strong>id</strong>: Tipo <code>INTEGER</code>. Marca las casillas <strong>PK</strong> (Primary Key) y <strong>AI</strong> (Autoincrement). Esto hará que cada juego tenga un número único automáticamente (1, 2, 3...).</li><li><strong>titulo</strong>: Tipo <code>TEXT</code>.</li><li><strong>empresa</strong>: Tipo <code>TEXT</code>.</li><li><strong>anio</strong>: Tipo <code>INTEGER</code>.</li><li><strong>precio</strong>: Tipo <code>REAL</code>.</li></ul></li></ol><h4 id="codigo-sql-que-genera-la-herramienta-automatico" tabindex="-1">Código SQL que genera la herramienta (automático): <a class="header-anchor" href="#codigo-sql-que-genera-la-herramienta-automatico" aria-label="Permalink to &quot;Código SQL que genera la herramienta (automático):&quot;">​</a></h4><p>Aunque lo hagas con clics, DB Browser está escribiendo este código por ti:</p><p>SQL</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CREATE TABLE &quot;videojuegos&quot; (</span></span>
<span class="line"><span>	&quot;id&quot;	INTEGER NOT NULL,</span></span>
<span class="line"><span>	&quot;titulo&quot;	TEXT NOT NULL,</span></span>
<span class="line"><span>	&quot;empresa&quot;	TEXT,</span></span>
<span class="line"><span>	&quot;anio&quot;	INTEGER,</span></span>
<span class="line"><span>	&quot;precio&quot;	REAL,</span></span>
<span class="line"><span>	PRIMARY KEY(&quot;id&quot; AUTOINCREMENT)</span></span>
<span class="line"><span>);</span></span></code></pre></div><h3 id="_2-4-insertando-nuestros-primeros-datos" tabindex="-1">2.4. Insertando nuestros primeros datos <a class="header-anchor" href="#_2-4-insertando-nuestros-primeros-datos" aria-label="Permalink to &quot;2.4. Insertando nuestros primeros datos&quot;">​</a></h3><p>Ahora que tenemos la estructura (el &quot;molde&quot;), vamos a meter contenido. En DB Browser, ve a la pestaña <strong>&quot;Hoja de datos&quot;</strong>.</p><ol><li>Haz clic en el icono de <strong>&quot;Añadir registro&quot;</strong> (un icono con un destello amarillo).</li><li>Rellena los campos. El <code>id</code> déjalo vacío, se pondrá solo.</li><li>Escribe: <code>Elden Ring</code>, <code>FromSoftware</code>, <code>2022</code>, <code>59.99</code>.</li><li><strong>¡IMPORTANTE!:</strong> Para que los cambios se guarden en el archivo, debes dar al botón <strong>&quot;Escribir cambios&quot;</strong> en la barra superior. Si cierras sin darle, perderás el trabajo.</li></ol><blockquote><p>💡 <strong>Nota:</strong> Fíjate que esto es idéntico a lo que hacías en el <code>db.json</code>, pero aquí el programa te obliga a respetar los tipos de datos y no te deja dejar el <code>id</code> vacío.</p></blockquote><h3 id="_2-5-resumen-de-la-sesion" tabindex="-1">2.5. Resumen de la sesión <a class="header-anchor" href="#_2-5-resumen-de-la-sesion" aria-label="Permalink to &quot;2.5. Resumen de la sesión&quot;">​</a></h3><ul><li>Hemos pasado de un fichero de texto (<code>.json</code>) a un fichero de base de datos (<code>.db</code>).</li><li>Hemos usado <strong>DB Browser</strong> como interfaz profesional.</li><li>Hemos definido <strong>tipos de datos</strong> para evitar errores humanos.</li></ul><p><strong>Comparativa final:</strong></p><ul><li><strong>ANTES:</strong> Abrías el Bloc de Notas y escribías <code>{ &quot;titulo&quot;: &quot;...&quot; }</code>.</li><li><strong>AHORA:</strong> Usas una herramienta que valida que el año sea un número y el precio tenga decimales</li></ul><p>Esta es la sesión central de la unidad. Aquí es donde ocurre la &quot;magia&quot;: vamos a aprender a pedirle datos a la base de datos y, lo más importante, a <strong>obligar a la base de datos a que nos responda en JSON</strong>.</p><p>De esta forma, vuestro código de JavaScript (<code>fetch</code>) no notará la diferencia entre el antiguo <code>db.json</code> y la nueva base de datos profesional.</p><h2 id="_3-consultas-sql-y-salida-en-json" tabindex="-1">3. Consultas SQL y salida en JSON <a class="header-anchor" href="#_3-consultas-sql-y-salida-en-json" aria-label="Permalink to &quot;3. Consultas SQL y salida en JSON&quot;">​</a></h2><h3 id="_3-1-repaso-hablando-con-la-base-de-datos-sql" tabindex="-1">3.1. Repaso: Hablando con la base de datos (SQL) <a class="header-anchor" href="#_3-1-repaso-hablando-con-la-base-de-datos-sql" aria-label="Permalink to &quot;3.1. Repaso: Hablando con la base de datos (SQL)&quot;">​</a></h3><p>Antes de convertir a JSON, necesitamos recordar cómo filtrar datos. Imaginad que nuestra tabla <code>videojuegos</code> ya tiene 20 o 30 filas.</p><p><strong>Ejemplo 1: Filtrar por año y ordenar</strong></p><p>Queremos los juegos de 2023, ordenados del más barato al más caro.</p><p>SQL</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SELECT titulo, precio </span></span>
<span class="line"><span>FROM videojuegos </span></span>
<span class="line"><span>WHERE anio = 2023 </span></span>
<span class="line"><span>ORDER BY precio ASC;</span></span></code></pre></div><p><strong>Ejemplo 2: Búsqueda flexible (LIKE)</strong></p><p>Queremos buscar cualquier juego que contenga la palabra &quot;Mario&quot;.</p><p>SQL</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SELECT * FROM videojuegos </span></span>
<span class="line"><span>WHERE titulo LIKE &#39;%Mario%&#39;;</span></span></code></pre></div><blockquote><p>💡 <strong>Nota:</strong> El símbolo <code>%</code> es un comodín. <code>%Mario%</code> significa &quot;cualquier cosa que tenga Mario en medio, al principio o al final&quot;.</p></blockquote><h3 id="_3-2-transformando-sql-a-json" tabindex="-1">3.2. Transformando SQL a JSON <a class="header-anchor" href="#_3-2-transformando-sql-a-json" aria-label="Permalink to &quot;3.2. Transformando SQL a JSON&quot;">​</a></h3><p>Aquí es donde conectamos este módulo con lo que ya sabéis. SQLite tiene funciones que crean el JSON por nosotros.</p><h4 id="a-la-funcion-json-object" tabindex="-1">A. La función <code>json_object()</code> <a class="header-anchor" href="#a-la-funcion-json-object" aria-label="Permalink to &quot;A. La función \`json_object()\`&quot;">​</a></h4><p>Esta función crea un <strong>objeto</strong> <code>{ }</code>. Debemos pasarle parejas de &quot;Clave&quot;, Valor.</p><p>SQL</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SELECT json_object(</span></span>
<span class="line"><span>  &#39;id&#39;, id,</span></span>
<span class="line"><span>  &#39;nombre_juego&#39;, titulo,</span></span>
<span class="line"><span>  &#39;precio_venta&#39;, precio</span></span>
<span class="line"><span>) </span></span>
<span class="line"><span>FROM videojuegos;</span></span></code></pre></div><p><strong>Resultado en la tabla:</strong></p><table tabindex="0"><thead><tr><th><strong>json_object(...)</strong></th></tr></thead><tbody><tr><td><code>{&quot;id&quot;:1,&quot;nombre_juego&quot;:&quot;Elden Ring&quot;,&quot;precio_venta&quot;:59.99}</code></td></tr><tr><td><code>{&quot;id&quot;:2,&quot;nombre_juego&quot;:&quot;Portal 2&quot;,&quot;precio_venta&quot;:9.99}</code></td></tr></tbody></table><h4 id="b-la-funcion-json-group-array" tabindex="-1">B. La función <code>json_group_array()</code> <a class="header-anchor" href="#b-la-funcion-json-group-array" aria-label="Permalink to &quot;B. La función \`json_group_array()\`&quot;">​</a></h4><p>Vuestro JavaScript normalmente espera un <strong>Array</strong> <code>[ ]</code> de objetos. Esta función &quot;empaqueta&quot; todas las filas en una sola lista.</p><p>SQL</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SELECT json_group_array(</span></span>
<span class="line"><span>  json_object(</span></span>
<span class="line"><span>    &#39;id&#39;, id,</span></span>
<span class="line"><span>    &#39;titulo&#39;, titulo</span></span>
<span class="line"><span>  )</span></span>
<span class="line"><span>)</span></span>
<span class="line"><span>FROM videojuegos;</span></span></code></pre></div><p><strong>Resultado:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[{&quot;id&quot;:1,&quot;titulo&quot;:&quot;Elden Ring&quot;},{&quot;id&quot;:2,&quot;titulo&quot;:&quot;Portal 2&quot;}]</span></span></code></pre></div><blockquote><p>⚠️ <strong>Cuidado:</strong> <code>json_group_array</code> es una función de agregado. Si la usáis, veréis que todas las filas de la tabla se comprimen en una sola celda que contiene el array completo. ¡Es justo lo que necesita un <code>fetch</code>!</p></blockquote><h4 id="c-la-funcion-json-extract" tabindex="-1">C. La función <code>json_extract()</code> <a class="header-anchor" href="#c-la-funcion-json-extract" aria-label="Permalink to &quot;C. La función \`json_extract()\`&quot;">​</a></h4><p>A veces, dentro de una tabla de SQLite, guardamos un texto que ya es un JSON. Con <code>json_extract</code> podemos sacar solo una parte.</p><p><em>Ejemplo: Si en la columna <code>detalles</code> guardamos <code>{&quot;color&quot;: &quot;rojo&quot;, &quot;stock&quot;: 5}</code>, podemos hacer:</em></p><p>SQL</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SELECT json_extract(detalles, &#39;$.stock&#39;) FROM videojuegos;</span></span></code></pre></div><h3 id="_3-3-importar-datos-de-json-server-a-sqlite" tabindex="-1">3.3. Importar datos de JSON-Server a SQLite <a class="header-anchor" href="#_3-3-importar-datos-de-json-server-a-sqlite" aria-label="Permalink to &quot;3.3. Importar datos de JSON-Server a SQLite&quot;">​</a></h3><p>Si ya tenéis un archivo <code>db.json</code> de vuestros proyectos anteriores, no tenéis que escribirlo todo de nuevo.</p><p><strong>Pasos en DB Browser:</strong></p><ol><li>En vuestro editor de código (VS Code), abrid el <code>db.json</code>.</li><li>Como DB Browser no importa JSON directamente de forma fácil, lo mejor es <strong>convertirlo a CSV</strong> (puedes usar un conversor online &quot;JSON to CSV&quot;).</li><li>En DB Browser: <strong>Archivo -&gt; Importar -&gt; Tabla desde archivo CSV...</strong></li><li>Seleccionáis vuestro archivo y ¡listo!, ya tenéis vuestra tabla creada con todos vuestros juegos.</li></ol><h3 id="_3-4-exportar-el-resultado-a-json" tabindex="-1">3.4. Exportar el resultado a JSON <a class="header-anchor" href="#_3-4-exportar-el-resultado-a-json" aria-label="Permalink to &quot;3.4. Exportar el resultado a JSON&quot;">​</a></h3><p>Una vez que hayáis hecho una consulta (Query) en la pestaña &quot;Ejecutar SQL&quot;, podéis guardar ese resultado para usarlo en vuestro frontend:</p><ol><li>Haced la consulta (por ejemplo, la del <code>json_group_array</code>).</li><li>Haced clic en el botón pequeño de la derecha que parece un disquete o pulsad botón derecho sobre el resultado.</li><li>Elegid <strong>&quot;Exportar a JSON&quot;</strong>.</li></ol><hr><h3 id="ejemplo-completo-paso-a-paso" tabindex="-1">Ejemplo Completo Paso a Paso <a class="header-anchor" href="#ejemplo-completo-paso-a-paso" aria-label="Permalink to &quot;Ejemplo Completo Paso a Paso&quot;">​</a></h3><p>Imagina que el jefe te pide: <em>&quot;Dame un fichero JSON con los juegos de &#39;Nintendo&#39; ordenados por año&quot;</em>.</p><p><strong>Paso 1: Escribimos la consulta SQL normal</strong></p><p>SQL</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SELECT * FROM videojuegos WHERE empresa = &#39;Nintendo&#39; ORDER BY anio DESC;</span></span></code></pre></div><p><strong>Paso 2: La envolvemos en funciones JSON</strong></p><p>SQL</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SELECT json_group_array(</span></span>
<span class="line"><span>  json_object(</span></span>
<span class="line"><span>    &#39;title&#39;, titulo,</span></span>
<span class="line"><span>    &#39;year&#39;, anio</span></span>
<span class="line"><span>  )</span></span>
<span class="line"><span>)</span></span>
<span class="line"><span>FROM videojuegos </span></span>
<span class="line"><span>WHERE empresa = &#39;Nintendo&#39; </span></span>
<span class="line"><span>ORDER BY anio DESC;</span></span></code></pre></div><p><strong>Paso 3: Exportamos</strong></p><p>Guardamos el resultado como <code>nintendo_games.json</code>. ¡Ya tenemos el fichero listo para nuestra web!</p><p>¡Damos un giro de 180 grados! Hasta ahora hemos visto bases de datos que parecen hojas de Excel (filas y columnas). Pero, ¿qué pasa si os digo que existe una forma de guardar los datos <strong>exactamente igual</strong> a como los escribís en vuestro código JavaScript?</p><p>Bienvenidos al mundo de las bases de datos <strong>NoSQL</strong>.</p><h2 id="_4-bases-de-datos-documentales-mongodb-atlas" tabindex="-1">4. Bases de datos documentales: MongoDB Atlas <a class="header-anchor" href="#_4-bases-de-datos-documentales-mongodb-atlas" aria-label="Permalink to &quot;4. Bases de datos documentales: MongoDB Atlas&quot;">​</a></h2><h3 id="_4-1-¿que-es-una-base-de-datos-documental" tabindex="-1">4.1. ¿Qué es una base de datos documental? <a class="header-anchor" href="#_4-1-¿que-es-una-base-de-datos-documental" aria-label="Permalink to &quot;4.1. ¿Qué es una base de datos documental?&quot;">​</a></h3><p>Imagina que en tu catálogo de videojuegos tienes un &quot;Simulador de Granja&quot; y un &quot;Shooter Espacial&quot;. El de granja tiene un campo llamado <code>numero_de_cultivos</code>, pero el shooter tiene <code>calibre_de_armas</code>.</p><p>En <strong>SQLite (Relacional)</strong>, estarías obligado a tener ambas columnas en la tabla, y muchas filas estarían vacías (<code>NULL</code>).</p><p>En <strong>MongoDB (Documental)</strong>, cada videojuego es un &quot;documento&quot; independiente. Si un juego necesita un campo extra, se lo pones y listo. No molestas a los demás.</p><h4 id="comparativa-relacional-vs-documental" tabindex="-1">Comparativa: Relacional vs. Documental <a class="header-anchor" href="#comparativa-relacional-vs-documental" aria-label="Permalink to &quot;Comparativa: Relacional vs. Documental&quot;">​</a></h4><table tabindex="0"><thead><tr><th><strong>Concepto</strong></th><th><strong>SQLite (Relacional)</strong></th><th><strong>MongoDB (Documental)</strong></th></tr></thead><tbody><tr><td><strong>Donde se guarda</strong></td><td>Tabla</td><td><strong>Colección</strong></td></tr><tr><td><strong>Cada registro</strong></td><td>Fila (Row)</td><td><strong>Documento</strong></td></tr><tr><td><strong>Formato</strong></td><td>Rígido (Columnas fijas)</td><td><strong>Flexible (JSON)</strong></td></tr><tr><td><strong>Lenguaje</strong></td><td>SQL</td><td><strong>MQL (MongoDB Query Language)</strong></td></tr></tbody></table><h3 id="_4-2-¿por-que-usar-mongodb" tabindex="-1">4.2. ¿Por qué usar MongoDB? <a class="header-anchor" href="#_4-2-¿por-que-usar-mongodb" aria-label="Permalink to &quot;4.2. ¿Por qué usar MongoDB?&quot;">​</a></h3><p>Se utiliza en aplicaciones donde los datos cambian rápido o no sabemos exactamente qué forma tendrán en el futuro.</p><ul><li><strong>Velocidad de desarrollo:</strong> Guardas el objeto JSON tal cual sale de tu formulario web.</li><li><strong>Escalabilidad:</strong> Está pensada para vivir en la nube y crecer hasta manejar millones de datos fácilmente.</li></ul><h3 id="_4-3-mongodb-atlas-tu-base-de-datos-en-la-nube" tabindex="-1">4.3. MongoDB Atlas: Tu base de datos en la nube <a class="header-anchor" href="#_4-3-mongodb-atlas-tu-base-de-datos-en-la-nube" aria-label="Permalink to &quot;4.3. MongoDB Atlas: Tu base de datos en la nube&quot;">​</a></h3><p>No vamos a instalar nada. Vamos a usar <strong>MongoDB Atlas</strong>, que es la versión &quot;Cloud&quot;. Es como tener un servidor profesional gratis para vuestros proyectos.</p><p><strong>Paso 1: Crear la cuenta y el Cluster</strong></p><ol><li>Entra en <a href="https://www.google.com/search?q=https://www.mongodb.com/cloud/atlas/lp/general/try" target="_blank" rel="noreferrer">mongodb.com/atlas</a> y regístrate gratis.</li><li>Crea un nuevo <strong>Cluster</strong> (elige el plan &quot;M0&quot;, que es el gratuito).</li><li>Selecciona un proveedor (como AWS) y una región cercana (Frankfurt o Irlanda).</li></ol><p><strong>Paso 2: Crear la base de datos y la colección</strong></p><ol><li>Una vez creado el cluster, ve a <strong>&quot;Browse Collections&quot;</strong>.</li><li>Pulsa en <strong>&quot;Add My Own Data&quot;</strong>.</li><li><strong>Database Name:</strong> <code>TiendaVideojuegos</code></li><li><strong>Collection Name:</strong> <code>Catalogo</code></li></ol><h3 id="_4-4-insertar-y-consultar-desde-la-interfaz" tabindex="-1">4.4. Insertar y Consultar desde la interfaz <a class="header-anchor" href="#_4-4-insertar-y-consultar-desde-la-interfaz" aria-label="Permalink to &quot;4.4. Insertar y Consultar desde la interfaz&quot;">​</a></h3><p>Aquí no usaremos código, solo la interfaz visual de Atlas.</p><h4 id="a-insertar-datos" tabindex="-1">A. Insertar datos <a class="header-anchor" href="#a-insertar-datos" aria-label="Permalink to &quot;A. Insertar datos&quot;">​</a></h4><p>Pulsa en <strong>&quot;Insert Document&quot;</strong>. Verás que puedes escribir directamente en formato JSON. Prueba a pegar esto:</p><p>JSON</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{</span></span>
<span class="line"><span>  &quot;titulo&quot;: &quot;Cyberpunk 2077&quot;,</span></span>
<span class="line"><span>  &quot;desarrollador&quot;: &quot;CD Projekt Red&quot;,</span></span>
<span class="line"><span>  &quot;tags&quot;: [&quot;Mundo Abierto&quot;, &quot;RPG&quot;, &quot;Sci-Fi&quot;],</span></span>
<span class="line"><span>  &quot;lanzamiento&quot;: 2020,</span></span>
<span class="line"><span>  &quot;metacritic&quot;: 86</span></span>
<span class="line"><span>}</span></span></code></pre></div><blockquote><p>💡 <strong>Nota:</strong> Fíjate que el campo <code>tags</code> es un <strong>Array</strong>. En SQLite esto sería muy difícil de hacer, ¡aquí es natural!</p></blockquote><h4 id="b-filtrar-consultar" tabindex="-1">B. Filtrar (Consultar) <a class="header-anchor" href="#b-filtrar-consultar" aria-label="Permalink to &quot;B. Filtrar (Consultar)&quot;">​</a></h4><p>En la parte superior verás una barra que dice <strong>&quot;Filter&quot;</strong>. Para buscar, tienes que usar el formato de llaves <code>{ }</code>.</p><ul><li><strong>Para buscar por título:</strong> <code>{ &quot;titulo&quot;: &quot;Cyberpunk 2077&quot; }</code></li><li><strong>Para buscar juegos modernos:</strong> <code>{ &quot;lanzamiento&quot;: { &quot;$gt&quot;: 2021 } }</code> (Ese <code>$gt</code> significa &quot;Greater Than&quot;, es decir, mayor que).</li></ul><blockquote><p>⚠️ <strong>Cuidado:</strong> MongoDB diferencia entre mayúsculas y minúsculas. Si buscas <code>{ &quot;titulo&quot;: &quot;cyberpunk&quot; }</code> (en minúscula), ¡no encontrará nada!</p></blockquote><h3 id="_4-5-resumen-de-la-sesion" tabindex="-1">4.5. Resumen de la sesión <a class="header-anchor" href="#_4-5-resumen-de-la-sesion" aria-label="Permalink to &quot;4.5. Resumen de la sesión&quot;">​</a></h3><ul><li>Hemos aprendido que <strong>MongoDB</strong> no usa tablas, sino <strong>colecciones de documentos JSON</strong>.</li><li>Es mucho más <strong>flexible</strong> que SQL para datos que cambian.</li><li>Hemos configurado un servidor real en la <strong>nube (Atlas)</strong> y hemos insertado datos manualmente</li></ul><h2 id="proyecto-final-gamevault" tabindex="-1">Proyecto Final: &quot;GameVault&quot; <a class="header-anchor" href="#proyecto-final-gamevault" aria-label="Permalink to &quot;Proyecto Final: &quot;GameVault&quot;&quot;">​</a></h2><p><strong>Misión:</strong> Construir un sistema de almacenamiento robusto que permita gestionar videojuegos, clasificarlos por géneros y preparar los datos para ser consumidos por una aplicación web mediante JSON.</p><h3 id="fase-1-la-base-de-datos-relacional-sqlite" tabindex="-1">Fase 1: La Base de Datos Relacional (SQLite) <a class="header-anchor" href="#fase-1-la-base-de-datos-relacional-sqlite" aria-label="Permalink to &quot;Fase 1: La Base de Datos Relacional (SQLite)&quot;">​</a></h3><p>Tu primera tarea es crear la estructura en <strong>DB Browser for SQLite</strong>. Para que los datos no estén &quot;sueltos&quot;, vamos a usar dos tablas relacionadas.</p><ol><li>Crea una base de datos llamada <code>GameVault.db</code>.</li><li><strong>Tabla <code>generos</code></strong>: Crea esta tabla con los campos <code>id</code> (PK, Autoincrement) y <code>nombre_genero</code> (TEXT).</li><li><strong>Tabla <code>videojuegos</code></strong>: Crea esta tabla con: <ul><li><code>id</code> (PK, Autoincrement).</li><li><code>titulo</code> (TEXT).</li><li><code>anio</code> (INTEGER).</li><li><code>id_genero</code> (INTEGER).</li></ul></li><li><strong>Inserción de datos</strong>: <ul><li>Introduce al menos <strong>3 géneros</strong> (ej: RPG, Acción, Aventuras).</li><li>Introduce al menos <strong>10 videojuegos</strong>. Asegúrate de que en la columna <code>id_genero</code> pones el número del género que le corresponde.</li></ul></li></ol><blockquote><p>💡 <strong>Nota:</strong> Por ejemplo, si el género &quot;RPG&quot; tiene el <code>id: 1</code>, todos los juegos que sean RPG deberán tener un <code>1</code> en su columna <code>id_genero</code>. Esto es lo que llamamos una <strong>Clave Foránea (FK)</strong>.</p></blockquote><h3 id="fase-2-consultas-y-exportacion-json" tabindex="-1">Fase 2: Consultas y Exportación JSON <a class="header-anchor" href="#fase-2-consultas-y-exportacion-json" aria-label="Permalink to &quot;Fase 2: Consultas y Exportación JSON&quot;">​</a></h3><p>Ahora que tienes los datos, vamos a extraerlos de forma que tu Frontend (JavaScript) los entienda. Debes realizar las siguientes consultas en la pestaña &quot;Ejecutar SQL&quot; y <strong>exportar cada resultado como un fichero <code>.json</code> independiente</strong>:</p><ol><li><strong>Consulta Global:</strong> Todos los juegos ordenados por título. (Archivo: <code>todos_los_juegos.json</code>)</li><li><strong>Filtro por Género:</strong> Selecciona solo los juegos cuyo <code>id_genero</code> sea el de tu género favorito. (Archivo: <code>juegos_filtrados.json</code>)</li><li><strong>Búsqueda:</strong> Usa <code>LIKE</code> para encontrar juegos que contengan una palabra específica (ej: &quot;Zelda&quot; o &quot;Duty&quot;). (Archivo: <code>busqueda.json</code>)</li><li><strong>La Súper Consulta JSON:</strong> Usa <code>json_group_array</code> y <code>json_object</code> para generar un array de objetos que contenga el <code>titulo</code> y el <code>anio</code> de todos los juegos. (Archivo: <code>formato_profesional.json</code>)</li></ol><h3 id="fase-3-el-almacen-en-la-nube-mongodb-atlas" tabindex="-1">Fase 3: El Almacén en la Nube (MongoDB Atlas) <a class="header-anchor" href="#fase-3-el-almacen-en-la-nube-mongodb-atlas" aria-label="Permalink to &quot;Fase 3: El Almacén en la Nube (MongoDB Atlas)&quot;">​</a></h3><p>Para demostrar que sabes manejar tecnologías modernas <strong>NoSQL</strong>, vamos a subir parte de tu catálogo a la nube.</p><ol><li>En tu cluster de <strong>MongoDB Atlas</strong>, crea una base de datos llamada <code>VaultCloud</code> y una colección llamada <code>Favoritos</code>.</li><li>Inserta manualmente <strong>5 videojuegos</strong> de tu lista. <ul><li><strong>Reto:</strong> Al menos dos de ellos deben tener un campo extra que no exista en los demás (ej: <code>&quot;dlc&quot;: true</code> o <code>&quot;plataformas&quot;: [&quot;PC&quot;, &quot;PS5&quot;]</code>). ¡Aprovecha la flexibilidad de JSON!</li></ul></li><li>Realiza una consulta desde la interfaz de Atlas para filtrar juegos por un año concreto y haz una <strong>captura de pantalla</strong>.</li></ol><h3 id="que-debes-entregar" tabindex="-1">Qué debes entregar <a class="header-anchor" href="#que-debes-entregar" aria-label="Permalink to &quot;Qué debes entregar&quot;">​</a></h3><p>Debes comprimir en un <code>.zip</code> los siguientes archivos:</p><ol><li><code>GameVault.db</code> (El archivo de base de datos de SQLite).</li><li>Los <strong>4 archivos .json</strong> exportados en la Fase 2.</li><li>Un documento (PDF o Markdown) con la <strong>captura de pantalla</strong> de tu consulta en MongoDB Atlas y una breve explicación de por qué es más flexible que SQLite (Criterios a, b, c).</li></ol><h3 id="rubrica-de-evaluacion-total-10-puntos" tabindex="-1">Rúbrica de Evaluación (Total: 10 puntos) <a class="header-anchor" href="#rubrica-de-evaluacion-total-10-puntos" aria-label="Permalink to &quot;Rúbrica de Evaluación (Total: 10 puntos)&quot;">​</a></h3><table tabindex="0"><thead><tr><th><strong>Apartado</strong></th><th><strong>Indicador de logro</strong></th><th><strong>Puntos</strong></th></tr></thead><tbody><tr><td><strong>Diseño DB</strong></td><td>Tablas creadas con tipos correctos y relación <code>id_genero</code> funcional.</td><td>2 pts</td></tr><tr><td><strong>SQL Básico</strong></td><td>Realiza correctamente los filtros, ordenación y el uso de <code>LIKE</code>.</td><td>2 pts</td></tr><tr><td><strong>Funciones JSON</strong></td><td>Uso correcto de <code>json_object</code> y <code>json_group_array</code> en la consulta 4.</td><td>2 pts</td></tr><tr><td><strong>MongoDB Atlas</strong></td><td>Colección creada en la nube con documentos flexibles y filtros aplicados.</td><td>2 pts</td></tr><tr><td><strong>Conceptos (a,b,c)</strong></td><td>Identifica correctamente ventajas/inconvenientes de cada sistema en la entrega.</td><td>1 pts</td></tr><tr><td><strong>Calidad Datos</strong></td><td>Los datos son coherentes, sin errores de sintaxis y bien organizados.</td><td>1 pts</td></tr></tbody></table>`,163)]))}const m=a(n,[["render",r]]);export{g as __pageData,m as default};
